  ('social-worker-moex-01264', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '史金納（Skinner）認為，行為建立來自於刺激與反應的聯結，此種聯結是建基於下列那兩種方式？', '["增強或處罰", "模仿或創作", "理解或記憶", "認知或注意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
