  ('social-worker-moex-01267', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會快速變遷，家庭面對巨大挑戰與危機，但每個家庭都具有其「家庭韌性（familyresilience）」。 下列選項何者非屬強化「家庭韌性」的關鍵要素？', '["家庭會尋找負向經驗意義，並發展對負向經驗的理解", "家庭擁有從負向經驗中回復的力量", "等待家庭生命週期的運轉", "家庭從他們的社區關係網絡中受惠"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01268', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「愛情發展輪轉理論（WheelTheoryofLoveDevelopment）」解釋交友與形成愛的過程。依據該 論述，下列過程順序何者比較正確？', '["彼此表露自己、互賴、產生親和之感、達成親密感情及基本人格需求", "產生親和之感、彼此表露自己、互賴、達成親密感情及基本人格需求", "互賴、彼此表露自己、產生親和之感、達成親密感情及基本人格需求", "彼此表露自己、產生親和之感、互賴、達成親密感情及基本人格需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
